er plugin'=>'Lägg till kompatibilitet med Ultimate Member-plugin','WPEngine Integration'=>'WPEngine Integration','Add compatibility with the WPEngine object cache.'=>'Lägg till kompatibilitet med WPEngine objektcache.','Yoast SEO Integration'=>'Yoast SEO-integration','Add compatibility with the Yoast SEO plugin'=>'Lägg till kompatibilitet med Yoast SEO-pluginet','Comment counts'=>'Kommentarantal','Prev'=>'Föregående','Next'=>'Nästa','Post not found for the author'=>'Inlägget hittades inte för författaren','Published date'=>'Publiceringsdatum','If you like %1$s please leave us a %2$s rating. Thank you!'=>'Om du gillar %1$s, vänligen ge oss en %2$s-betyg. Tack!','About'=>'Om','Documentation'=>'Dokumentation','Contact'=>'Kontakta','taxonomy general nameAuthors'=>'Författare','taxonomy singular nameAuthor'=>'Författare','Author Box post type name%2$s'=>'%2$s','singular author box post type name%1$s'=>'%1$s','custom layout post type menu name%2$s'=>'%2$s','Custom Field post type name%2$s'=>'%2$s','singular custom field post type name%1$s'=>'%1$s','custom field post type menu name%2$s'=>'%2$s']];